interface GeneratedQ {
  stem: string;
  options: string[];
  correctAnswer: number;
  rationale: string;
  learningObjective: string;
  blueprintCategory: string;
  subtopic: string;
  difficulty: number;
  cognitiveLevel: string;
  questionType: "multiple-choice" | "image-interpretation" | "calculation" | "clinical-case";
  scenario?: string;
  caseId?: string;
  exhibitData?: any;
  exam: string;
  regionScope: "US" | "CAN" | "BOTH";
}

interface QuestionTemplate {
  stemTemplate: string;
  options: string[];
  correctAnswer: number;
  rationale: string;
  learningObjective: string;
  blueprintCategory: string;
  subtopic: string;
  difficulty: number;
  cognitiveLevel: string;
  questionType: "multiple-choice" | "image-interpretation" | "calculation" | "clinical-case";
  scenario?: string;
  exhibitData?: any;
  exam: string;
  regionScope: "US" | "CAN" | "BOTH";
}

function createQ(t: QuestionTemplate): GeneratedQ {
  return {
    stem: t.stemTemplate,
    options: t.options,
    correctAnswer: t.correctAnswer,
    rationale: t.rationale,
    learningObjective: t.learningObjective,
    blueprintCategory: t.blueprintCategory,
    subtopic: t.subtopic,
    difficulty: t.difficulty,
    cognitiveLevel: t.cognitiveLevel,
    questionType: t.questionType,
    scenario: t.scenario,
    exhibitData: t.exhibitData,
    exam: t.exam,
    regionScope: t.regionScope,
  };
}

export function generateBatch4(): GeneratedQ[] {
  return [
    createQ({ stemTemplate: "The right coronary artery most commonly supplies the SA node in what percentage of patients?", options: ["40%", "55%", "60%", "85%"], correctAnswer: 3, rationale: "The SA node artery arises from the RCA in approximately 55-60% of patients and from the LCx in the remainder. The RCA is dominant (supplies the PDA) in approximately 85% of patients.", learningObjective: "Describe coronary artery dominance patterns", blueprintCategory: "Anatomy/Physiology", subtopic: "Coronary Artery Anatomy", difficulty: 3, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" }),
    createQ({ stemTemplate: "The fossa ovalis is located in which cardiac structure?", options: ["Interventricular septum", "Interatrial septum", "Right atrial free wall", "Left atrial roof"], correctAnswer: 1, rationale: "The fossa ovalis is a depression in the interatrial septum that marks the location of the foramen ovale. It is the thinnest part of the atrial septum and the most common site for secundum ASDs and PFOs.", learningObjective: "Locate the fossa ovalis", blueprintCategory: "Anatomy/Physiology", subtopic: "Cardiac Anatomy", difficulty: 1, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" }),
    createQ({ stemTemplate: "The pericardium normally contains how much fluid?", options: ["0 mL", "15-50 mL", "100-200 mL", "300-500 mL"], correctAnswer: 1, rationale: "The normal pericardial sac contains 15-50 mL of serous fluid that acts as a lubricant between the visceral and parietal pericardial layers. This small amount is not typically visible on echocardiography.", learningObjective: "State normal pericardial fluid volume", blueprintCategory: "Anatomy/Physiology", subtopic: "Pericardial Anatomy", difficulty: 1, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" }),
    createQ({ stemTemplate: "The bundle of His is located in which part of the cardiac conduction system?", options: ["SA node", "AV node", "Interventricular septum (membranous portion)", "Purkinje fibers"], correctAnswer: 2, rationale: "The bundle of His extends from the AV node through the membranous interventricular septum before dividing into the right and left bundle branches. Damage to this area during cardiac surgery or from septal pathology can cause heart block.", learningObjective: "Describe the location of the bundle of His", blueprintCategory: "Anatomy/Physiology", subtopic: "Cardiac Anatomy", difficulty: 2, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" }),
    createQ({ stemTemplate: "In a right-dominant circulation, the posterior descending artery arises from the:", options: ["Left anterior descending", "Left circumflex", "Right coronary artery", "Left main"], correctAnswer: 2, rationale: "In right-dominant circulation (85% of patients), the PDA arises from the RCA and supplies the inferior wall and posterior septum. In left-dominant circulation (8%), the PDA comes from the LCx. Co-dominant circulation (7%) has PDA contributions from both.", learningObjective: "Identify PDA origin by dominance type", blueprintCategory: "Anatomy/Physiology", subtopic: "Coronary Artery Anatomy", difficulty: 2, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" }),
    createQ({ stemTemplate: "The normal LA diameter measured in the parasternal long-axis view is:", options: ["<20 mm", "20-40 mm", "41-50 mm", ">50 mm"], correctAnswer: 1, rationale: "Normal LA anteroposterior diameter in the PLAX view is 20-40 mm. Mild dilation: 41-46 mm, moderate: 47-52 mm, severe: >52 mm. However, LA volume index (biplane) is the preferred measure of LA size per current guidelines.", learningObjective: "State normal LA diameter", blueprintCategory: "Anatomy/Physiology", subtopic: "Cardiac Anatomy", difficulty: 1, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" }),
    createQ({ stemTemplate: "Preload is defined as:", options: ["Pressure the ventricle must overcome during ejection", "Volume of blood in the ventricle at end-diastole", "Heart rate multiplied by stroke volume", "Resistance to ventricular outflow"], correctAnswer: 1, rationale: "Preload is the end-diastolic volume (or pressure) that stretches the ventricular myocardium before contraction. It determines the starting point on the Frank-Starling curve. On echo, LVEDV is the best measure of preload.", learningObjective: "Define preload", blueprintCategory: "Anatomy/Physiology", subtopic: "Cardiac Physiology", difficulty: 1, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" }),
    createQ({ stemTemplate: "Afterload is best represented by:", options: ["End-diastolic volume", "Heart rate", "Systemic vascular resistance (or wall stress)", "Venous return"], correctAnswer: 2, rationale: "Afterload is the resistance the ventricle must overcome during ejection, best approximated by systemic vascular resistance (SVR) or, more precisely, LV wall stress (incorporating LV pressure, radius, and wall thickness via the Laplace relationship).", learningObjective: "Define afterload", blueprintCategory: "Anatomy/Physiology", subtopic: "Cardiac Physiology", difficulty: 1, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" }),
    createQ({ stemTemplate: "The Law of Laplace states that wall stress is proportional to:", options: ["Wall thickness × pressure", "Pressure × radius / (2 × wall thickness)", "Frequency × wavelength", "Velocity × area"], correctAnswer: 1, rationale: "Wall stress = (Pressure × Radius) / (2 × Wall thickness). This explains why LV hypertrophy (increased wall thickness) reduces wall stress despite elevated pressure, and why dilated ventricles (increased radius) have increased wall stress.", learningObjective: "Apply the Law of Laplace to cardiac physiology", blueprintCategory: "Anatomy/Physiology", subtopic: "Cardiac Physiology", difficulty: 3, cognitiveLevel: "comprehension", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" }),
    createQ({ stemTemplate: "During the cardiac cycle, S2 (second heart sound) corresponds to:", options: ["Closure of the AV valves", "Opening of the AV valves", "Closure of the semilunar valves (aortic and pulmonic)", "Opening of the semilunar valves"], correctAnswer: 2, rationale: "S2 is produced by closure of the aortic and pulmonic valves at the end of systole, marking the onset of diastole. The aortic component (A2) normally precedes the pulmonic component (P2). Wide fixed splitting of S2 is characteristic of ASD.", learningObjective: "Correlate heart sounds with valve events", blueprintCategory: "Anatomy/Physiology", subtopic: "Cardiac Physiology", difficulty: 1, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" }),
    createQ({ stemTemplate: "Impedance in ultrasound is the product of:", options: ["Frequency × wavelength", "Density × propagation speed", "Power × time", "Amplitude × frequency"], correctAnswer: 1, rationale: "Acoustic impedance (Z) = density × propagation speed. Differences in impedance between tissues determine the amount of ultrasound reflected at interfaces. Greater impedance mismatch = more reflection. This is why gel eliminates the air-skin interface.", learningObjective: "Define acoustic impedance", blueprintCategory: "Ultrasound Physics", subtopic: "Echo Imaging Physics", difficulty: 2, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" }),
    createQ({ stemTemplate: "The piezoelectric effect is essential for ultrasound because it:", options: ["Produces X-rays", "Converts electrical energy to mechanical energy (sound waves) and vice versa", "Creates magnetic fields", "Generates heat for imaging"], correctAnswer: 1, rationale: "Piezoelectric crystals (PZT, lead zirconate titanate) convert electrical signals to mechanical vibrations (sound waves) for transmission and convert returning echoes (mechanical energy) back to electrical signals for processing. This bidirectional conversion is the foundation of ultrasound imaging.", learningObjective: "Explain the piezoelectric effect", blueprintCategory: "Ultrasound Physics", subtopic: "Echo Imaging Physics", difficulty: 2, cognitiveLevel: "comprehension", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" }),
    createQ({ stemTemplate: "The speed of sound in soft tissue is approximately:", options: ["330 m/s", "1000 m/s", "1540 m/s", "3000 m/s"], correctAnswer: 2, rationale: "The average speed of sound in soft tissue is 1540 m/s (1.54 mm/μs). Ultrasound machines assume this constant speed for all distance calculations. If actual speed differs (e.g., in fat or bone), distance errors occur.", learningObjective: "State the speed of sound in soft tissue", blueprintCategory: "Ultrasound Physics", subtopic: "Echo Imaging Physics", difficulty: 1, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" }),
    createQ({ stemTemplate: "Increasing ultrasound frequency will:", options: ["Increase penetration depth and decrease resolution", "Decrease penetration depth and increase resolution", "Have no effect on imaging", "Increase both penetration and resolution equally"], correctAnswer: 1, rationale: "Higher frequency provides better resolution (shorter wavelength) but less penetration (more attenuation). Lower frequency provides deeper penetration but lower resolution. This is the fundamental frequency-resolution-penetration trade-off.", learningObjective: "Describe the frequency-resolution trade-off", blueprintCategory: "Ultrasound Physics", subtopic: "Echo Imaging Physics", difficulty: 1, cognitiveLevel: "comprehension", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" }),
    createQ({ stemTemplate: "A reverberation artifact in echocardiography appears as:", options: ["A single bright echo", "Equally spaced parallel lines extending deep to a strong reflector", "A dark shadow", "Color bleeding outside the heart"], correctAnswer: 1, rationale: "Reverberation occurs when the ultrasound beam bounces repeatedly between two strong parallel reflectors (e.g., between the transducer and pericardium, or between prosthetic valve components). It produces equally spaced, parallel linear echoes of decreasing intensity extending deeper than the actual structure.", learningObjective: "Identify reverberation artifacts", blueprintCategory: "Ultrasound Physics", subtopic: "Echo Imaging Physics", difficulty: 2, cognitiveLevel: "comprehension", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" }),
    createQ({ stemTemplate: "What is the Doppler angle correction formula?", options: ["Δf = 2f₀v/c", "Δf = 2f₀v cos θ/c", "Δf = f₀/v", "Δf = v/2f₀"], correctAnswer: 1, rationale: "The Doppler equation: Δf = (2 × f₀ × v × cos θ) / c, where f₀ is transmitted frequency, v is blood velocity, θ is the angle between the beam and flow, and c is the speed of sound. At θ = 0°, cos θ = 1 (maximum Doppler shift). At θ = 90°, cos θ = 0 (no Doppler shift).", learningObjective: "State the Doppler equation", blueprintCategory: "Ultrasound Physics", subtopic: "Doppler Ultrasound", difficulty: 2, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" }),
    createQ({ stemTemplate: "Power Doppler compared to color Doppler:", options: ["Shows velocity information", "Is angle-dependent", "Detects flow presence without velocity or direction information, with higher sensitivity", "Has lower sensitivity to slow flow"], correctAnswer: 2, rationale: "Power Doppler (amplitude Doppler) displays the amplitude/power of the Doppler signal regardless of velocity or direction. It is angle-independent and more sensitive to slow flow. However, it provides no velocity or directional information. It is used to confirm flow presence in questionable areas.", learningObjective: "Compare power Doppler to color Doppler", blueprintCategory: "Ultrasound Physics", subtopic: "Doppler Ultrasound", difficulty: 3, cognitiveLevel: "comprehension", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" }),
    createQ({ stemTemplate: "The wall filter (high-pass filter) in Doppler is used to:", options: ["Remove high-velocity blood flow signals", "Remove low-velocity signals from wall motion and clutter", "Increase frame rate", "Improve lateral resolution"], correctAnswer: 1, rationale: "The wall filter removes low-frequency, high-amplitude signals generated by moving walls, valve leaflets, and other tissue motion (clutter). Setting it too high can remove legitimate low-velocity blood flow signals. Setting it too low allows clutter to contaminate the spectral display.", learningObjective: "Explain the wall filter function", blueprintCategory: "Ultrasound Physics", subtopic: "Doppler Ultrasound", difficulty: 2, cognitiveLevel: "comprehension", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" }),
    createQ({ stemTemplate: "The sample volume size in PW Doppler determines:", options: ["Maximum velocity detected", "The spatial region from which velocity data is collected", "The color map used", "The wall filter setting"], correctAnswer: 1, rationale: "The sample volume (gate) size in PW Doppler determines the axial length of the region from which Doppler data is collected. A smaller gate provides more precise spatial sampling (e.g., LVOT VTI). A larger gate captures a broader area but may include unwanted flow signals.", learningObjective: "Describe the PW Doppler sample volume", blueprintCategory: "Ultrasound Physics", subtopic: "Doppler Ultrasound", difficulty: 2, cognitiveLevel: "comprehension", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" }),
    createQ({ stemTemplate: "In the parasternal long-axis view, which structure is seen as a circular cross-section posterior to the left atrium?", options: ["Pulmonary artery", "Ascending aorta", "Descending thoracic aorta", "Coronary sinus"], correctAnswer: 2, rationale: "The descending thoracic aorta appears as a circular structure posterior to the LA in the PLAX view. It is an important landmark that helps distinguish the LA from the descending aorta and should not be confused with a mass or lymph node.", learningObjective: "Identify the descending aorta in PLAX view", blueprintCategory: "Ultrasound Physics", subtopic: "Echo Imaging Views", difficulty: 2, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" }),
    createQ({ stemTemplate: "The apical two-chamber view visualizes which structures?", options: ["All four chambers", "Left atrium and left ventricle only", "Right atrium and right ventricle only", "Both atria only"], correctAnswer: 1, rationale: "The apical two-chamber (A2C) view shows only the LA and LV, with the inferior wall (posterior) and anterior wall visualized. It is obtained by rotating 60° counterclockwise from the A4C view. This view is essential for biplane Simpson's EF calculation and evaluating the inferior and anterior wall motion.", learningObjective: "Describe the apical two-chamber view anatomy", blueprintCategory: "Ultrasound Physics", subtopic: "Echo Imaging Views", difficulty: 2, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" }),
    createQ({ stemTemplate: "The apical three-chamber (apical long-axis) view is equivalent to which parasternal view?", options: ["PSAX at mitral level", "PLAX from the apical window", "PSAX at aortic level", "Subcostal view"], correctAnswer: 1, rationale: "The A3C view shows the same structures as the PLAX (LV, LVOT, aortic valve, aortic root, LA, mitral valve) but from the apical window. It is obtained by rotating 60° clockwise from the A2C view and is useful for Doppler interrogation of the LVOT and aortic valve with optimal alignment.", learningObjective: "Correlate the A3C and PLAX views", blueprintCategory: "Ultrasound Physics", subtopic: "Echo Imaging Views", difficulty: 2, cognitiveLevel: "comprehension", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" }),
    createQ({ stemTemplate: "The right ventricular inflow view is obtained from:", options: ["Apical position", "Parasternal window, tilted medially and inferiorly", "Suprasternal notch", "Subcostal window only"], correctAnswer: 1, rationale: "The RV inflow view is obtained from the parasternal window by tilting the transducer medially and inferiorly to visualize the RA, tricuspid valve, and RV inflow tract. This view is useful for assessing tricuspid valve pathology and TR jet interrogation.", learningObjective: "Describe the RV inflow view acquisition", blueprintCategory: "Ultrasound Physics", subtopic: "Echo Imaging Views", difficulty: 3, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" }),
    createQ({ stemTemplate: "The right ventricular outflow tract (RVOT) view shows:", options: ["The RV, pulmonic valve, and proximal pulmonary artery", "Only the left ventricle", "The aortic root only", "The left atrial appendage"], correctAnswer: 0, rationale: "The RVOT (parasternal short-axis at basal level or dedicated RVOT view) shows the RVOT, pulmonic valve, and proximal pulmonary artery. RVOT VTI and diameter measurements from this view are used for Qp:Qs calculations.", learningObjective: "Describe the RVOT view anatomy", blueprintCategory: "Ultrasound Physics", subtopic: "Echo Imaging Views", difficulty: 2, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" }),
    createQ({ stemTemplate: "To reduce aliasing in PW Doppler without switching to CW Doppler, the sonographer can:", options: ["Decrease gain", "Shift the baseline and increase PRF", "Increase depth only", "Use a higher frequency transducer"], correctAnswer: 1, rationale: "Shifting the baseline allows full-scale display in one direction. Increasing PRF raises the Nyquist limit. Using a lower frequency transducer, decreasing depth, or using high-PRF PW mode also help. If aliasing persists, switch to CW Doppler.", learningObjective: "Apply techniques to reduce Doppler aliasing", blueprintCategory: "Ultrasound Physics", subtopic: "Doppler Ultrasound", difficulty: 2, cognitiveLevel: "application", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" }),
    createQ({ stemTemplate: "A peak aortic velocity of 2.5 m/s yields a peak gradient of:", options: ["10 mmHg", "20 mmHg", "25 mmHg", "36 mmHg"], correctAnswer: 2, rationale: "Peak gradient = 4V² = 4 × (2.5)² = 4 × 6.25 = 25 mmHg. This velocity is consistent with mild aortic stenosis (peak velocity 2.0-2.9 m/s, mean gradient <20 mmHg).", learningObjective: "Calculate peak gradient from Doppler velocity", blueprintCategory: "Hemodynamic Measurements", subtopic: "Hemodynamic Calculations", difficulty: 1, cognitiveLevel: "application", questionType: "calculation", exam: "RDCS-AE", regionScope: "BOTH" }),
    createQ({ stemTemplate: "If cardiac output is 5 L/min and heart rate is 80 bpm, the stroke volume is:", options: ["50 mL", "62.5 mL", "75 mL", "80 mL"], correctAnswer: 1, rationale: "SV = CO / HR = 5000 mL/min ÷ 80 = 62.5 mL. Normal SV is 60-100 mL. This is a straightforward application of the CO = SV × HR relationship.", learningObjective: "Calculate stroke volume from CO and HR", blueprintCategory: "Hemodynamic Measurements", subtopic: "Hemodynamic Calculations", difficulty: 1, cognitiveLevel: "application", questionType: "calculation", exam: "RDCS-AE", regionScope: "BOTH" }),
    createQ({ stemTemplate: "An EF of 40% with an EDV of 150 mL yields an ESV of:", options: ["60 mL", "75 mL", "90 mL", "110 mL"], correctAnswer: 2, rationale: "EF = (EDV - ESV) / EDV. 0.40 = (150 - ESV) / 150. ESV = 150 - (0.40 × 150) = 150 - 60 = 90 mL. Alternatively: SV = EF × EDV = 0.40 × 150 = 60 mL, ESV = EDV - SV = 150 - 60 = 90 mL.", learningObjective: "Calculate ESV from EF and EDV", blueprintCategory: "Hemodynamic Measurements", subtopic: "Hemodynamic Calculations", difficulty: 2, cognitiveLevel: "application", questionType: "calculation", exam: "RDCS-AE", regionScope: "BOTH" }),
    createQ({ stemTemplate: "Mean gradient across the aortic valve is calculated from the Doppler waveform by:", options: ["Peak velocity squared times 4", "Averaging instantaneous gradients throughout the ejection period (tracing the CW envelope)", "Dividing peak gradient by 2", "Multiplying VTI by valve area"], correctAnswer: 1, rationale: "Mean gradient is calculated by tracing the CW Doppler envelope throughout the systolic ejection period. The machine averages all instantaneous gradients (4V² at each time point) across the ejection period. Mean gradient is more clinically reliable than peak gradient.", learningObjective: "Describe mean gradient calculation", blueprintCategory: "Hemodynamic Measurements", subtopic: "Hemodynamic Calculations", difficulty: 2, cognitiveLevel: "comprehension", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" }),
    createQ({ stemTemplate: "Cardiac index is calculated as:", options: ["CO × BSA", "CO / BSA", "SV × HR × BSA", "HR / BSA"], correctAnswer: 1, rationale: "Cardiac index = Cardiac output / Body surface area. Normal CI is 2.5-4.0 L/min/m². CI <2.2 L/min/m² indicates significantly reduced cardiac output relative to body size. CI normalizes CO for patient size, allowing comparison across patients.", learningObjective: "Calculate cardiac index", blueprintCategory: "Hemodynamic Measurements", subtopic: "Hemodynamic Calculations", difficulty: 2, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" }),
    createQ({ stemTemplate: "The E/A ratio reversal pattern (E/A <1) is commonly seen in:", options: ["Healthy young adults", "Normal diastolic function in elderly patients or Grade I diastolic dysfunction", "Restrictive cardiomyopathy", "Mitral stenosis"], correctAnswer: 1, rationale: "E/A <1 (impaired relaxation pattern) is common in elderly patients as a normal aging change and in Grade I diastolic dysfunction. The ventricle relaxes more slowly, reducing early diastolic filling (E) and increasing dependence on atrial contraction (A).", learningObjective: "Interpret E/A reversal pattern", blueprintCategory: "Hemodynamic Measurements", subtopic: "Diastolic Function Assessment", difficulty: 2, cognitiveLevel: "comprehension", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" }),
    createQ({ stemTemplate: "Severe mitral regurgitation is defined by a regurgitant volume of:", options: ["≥20 mL", "≥30 mL", "≥45 mL", "≥60 mL"], correctAnswer: 3, rationale: "Severe MR: regurgitant volume ≥60 mL, regurgitant fraction ≥50%, EROA ≥0.40 cm². Moderate: RV 30-59 mL, RF 30-49%, EROA 0.20-0.39 cm². Mild: RV <30 mL, RF <30%, EROA <0.20 cm².", learningObjective: "State regurgitant volume criteria for severe MR", blueprintCategory: "Hemodynamic Measurements", subtopic: "Hemodynamic Calculations", difficulty: 2, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" }),
    createQ({ stemTemplate: "The mitral valve gradient in severe mitral stenosis is typically:", options: ["<5 mmHg", ">10 mmHg (mean gradient)", "2-3 mmHg", "Unmeasurable"], correctAnswer: 1, rationale: "In severe MS, the mean transmitral gradient is typically >10 mmHg (often 15-25 mmHg) depending on heart rate and cardiac output. Mild MS: mean gradient <5 mmHg. Moderate: 5-10 mmHg. Gradient increases with exercise or tachycardia.", learningObjective: "State typical gradients in severe mitral stenosis", blueprintCategory: "Hemodynamic Measurements", subtopic: "Hemodynamic Calculations", difficulty: 2, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" }),
    createQ({ stemTemplate: "The pressure half-time of 120 ms across the mitral valve corresponds to an MVA of:", options: ["0.9 cm²", "1.4 cm²", "1.8 cm²", "2.2 cm²"], correctAnswer: 2, rationale: "MVA = 220 / PHT = 220 / 120 = 1.83 cm² ≈ 1.8 cm². This value is consistent with mild mitral stenosis (MVA >1.5 cm²).", learningObjective: "Calculate MVA from pressure half-time", blueprintCategory: "Hemodynamic Measurements", subtopic: "Hemodynamic Calculations", difficulty: 2, cognitiveLevel: "application", questionType: "calculation", exam: "RDCS-AE", regionScope: "BOTH" }),
    createQ({ stemTemplate: "The dP/dt is measured from the MR CW Doppler jet between velocities of:", options: ["0 and 1 m/s", "1 and 3 m/s", "2 and 4 m/s", "3 and 5 m/s"], correctAnswer: 1, rationale: "dP/dt is measured between the 1 m/s and 3 m/s points on the MR CW Doppler upstroke. Pressure difference = 4(3²) - 4(1²) = 36 - 4 = 32 mmHg. dP/dt = 32 / time interval (in seconds). Normal dP/dt >1200 mmHg/s.", learningObjective: "Describe dP/dt measurement technique", blueprintCategory: "Hemodynamic Measurements", subtopic: "Hemodynamic Calculations", difficulty: 4, cognitiveLevel: "application", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" }),
    createQ({ stemTemplate: "Mild aortic stenosis is defined by an AVA of:", options: [">1.5 cm²", "1.0-1.5 cm²", "0.7-1.0 cm²", "<0.6 cm²"], correctAnswer: 0, rationale: "Mild AS: AVA >1.5 cm², peak velocity 2.0-2.9 m/s, mean gradient <20 mmHg. Moderate: AVA 1.0-1.5 cm², Vpeak 3.0-3.9, MG 20-39. Severe: AVA <1.0 cm², Vpeak ≥4.0, MG ≥40.", learningObjective: "State AVA criteria for mild AS", blueprintCategory: "Pathology Recognition", subtopic: "Valvular Disease Assessment", difficulty: 2, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" }),
    createQ({ stemTemplate: "In severe aortic regurgitation, the jet width to LVOT width ratio is:", options: [">25%", ">45%", ">65%", ">90%"], correctAnswer: 2, rationale: "Severe AR: jet width/LVOT width >65% in the PLAX view. This is the color Doppler jet width immediately below the aortic valve. Mild: <25%, moderate: 25-64%, severe: ≥65%. This is a simple screening parameter for AR severity.", learningObjective: "Apply jet width/LVOT criteria for AR severity", blueprintCategory: "Pathology Recognition", subtopic: "Valvular Disease Assessment", difficulty: 3, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" }),
    createQ({ stemTemplate: "The most common cause of aortic stenosis in patients over 70 years of age is:", options: ["Rheumatic heart disease", "Bicuspid aortic valve", "Degenerative calcific disease", "Congenital unicuspid valve"], correctAnswer: 2, rationale: "Degenerative calcific aortic stenosis is the most common cause in elderly patients (>70 years). Calcium deposits on the aortic side of the cusps restrict opening. Bicuspid AV is the most common cause in patients 40-70. Rheumatic AS is less common in developed countries.", learningObjective: "Identify the most common cause of AS by age group", blueprintCategory: "Pathology Recognition", subtopic: "Valvular Disease Assessment", difficulty: 2, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" }),
    createQ({ stemTemplate: "Mitral valve prolapse is most accurately diagnosed in which echocardiographic view?", options: ["Apical four-chamber", "Parasternal long-axis", "Parasternal short-axis", "Subcostal"], correctAnswer: 1, rationale: "MVP is diagnosed in the parasternal long-axis view by demonstrating ≥2 mm systolic displacement of the mitral leaflet above the annular plane. The apical four-chamber view can produce false-positive MVP due to the saddle shape of the mitral annulus.", learningObjective: "Select the correct view for MVP diagnosis", blueprintCategory: "Pathology Recognition", subtopic: "Valvular Disease Assessment", difficulty: 3, cognitiveLevel: "application", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" }),
    createQ({ stemTemplate: "Functional (secondary) mitral regurgitation is caused by:", options: ["Intrinsic valve disease", "LV dilation and remodeling causing leaflet tethering and annular dilation", "Rheumatic valve involvement", "Calcific degeneration of the valve"], correctAnswer: 1, rationale: "Functional MR occurs with structurally normal valve leaflets but abnormal LV geometry. LV dilation displaces the papillary muscles, tethering the leaflets (Carpentier Type IIIb) and dilating the annulus, preventing leaflet coaptation. Treating the underlying LV disease is the primary therapy.", learningObjective: "Distinguish functional from organic MR", blueprintCategory: "Pathology Recognition", subtopic: "Valvular Disease Assessment", difficulty: 3, cognitiveLevel: "comprehension", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" }),
    createQ({ stemTemplate: "Rheumatic tricuspid stenosis is characterized by echo finding of:", options: ["Isolated calcification", "Commissural fusion with thickened leaflets and diastolic doming", "Leaflet prolapse", "Annular dilation"], correctAnswer: 1, rationale: "Rheumatic tricuspid stenosis, though rare, shows the same commissural fusion with leaflet thickening and diastolic doming seen in rheumatic MS. It almost always occurs in conjunction with mitral valve involvement. Mean gradient >5 mmHg suggests significant TS.", learningObjective: "Identify echo findings of rheumatic TS", blueprintCategory: "Pathology Recognition", subtopic: "Valvular Disease Assessment", difficulty: 4, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" }),
    createQ({ stemTemplate: "In a patient with known VSD, Eisenmenger syndrome develops when:", options: ["The shunt reverses to right-to-left due to irreversible pulmonary vascular disease", "The VSD closes spontaneously", "The left-to-right shunt increases", "Aortic stenosis develops"], correctAnswer: 0, rationale: "Eisenmenger syndrome occurs when a chronic left-to-right shunt causes progressive pulmonary vascular remodeling, leading to irreversible pulmonary hypertension. When pulmonary pressure exceeds systemic pressure, the shunt reverses to right-to-left, causing cyanosis. Surgical closure is contraindicated at this stage.", learningObjective: "Describe Eisenmenger physiology", blueprintCategory: "Pathology Recognition", subtopic: "Congenital Heart Defects", difficulty: 4, cognitiveLevel: "comprehension", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" }),
    createQ({ stemTemplate: "A perimembranous VSD is located:", options: ["In the muscular septum", "Adjacent to the tricuspid valve annulus and aortic valve", "In the outlet septum below the pulmonic valve", "At the crux of the heart"], correctAnswer: 1, rationale: "Perimembranous VSDs (most common type, 80%) are located in the membranous septum near both the tricuspid and aortic valves. They may extend into the inlet, outlet, or trabecular septum. The proximity to the aortic valve can cause AR due to cusp prolapse into the defect.", learningObjective: "Locate perimembranous VSDs", blueprintCategory: "Pathology Recognition", subtopic: "Congenital Heart Defects", difficulty: 3, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" }),
    createQ({ stemTemplate: "Transposition of the great arteries (d-TGA) on echocardiography shows:", options: ["Normal great artery relationship", "The aorta arising from the right ventricle and the pulmonary artery from the left ventricle with parallel great arteries", "Single outlet from the heart", "Both great arteries from the left ventricle"], correctAnswer: 1, rationale: "In d-TGA, the aorta arises from the morphologic RV and the PA from the morphologic LV, creating two parallel circulations. The great arteries run parallel rather than crossing. Without mixing (via ASD, VSD, or PDA), it is incompatible with life.", learningObjective: "Describe echo findings of d-TGA", blueprintCategory: "Pathology Recognition", subtopic: "Congenital Heart Defects", difficulty: 4, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" }),
    createQ({ stemTemplate: "A partial anomalous pulmonary venous return (PAPVR) is most commonly associated with which type of ASD?", options: ["Secundum", "Primum", "Sinus venosus", "Coronary sinus type"], correctAnswer: 2, rationale: "PAPVR is most commonly associated with sinus venosus ASDs, particularly the superior type near the SVC junction. One or more right pulmonary veins drain anomalously into the SVC or RA instead of the LA. This combination causes right heart volume overload.", learningObjective: "Associate PAPVR with sinus venosus ASD", blueprintCategory: "Pathology Recognition", subtopic: "Congenital Heart Defects", difficulty: 4, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" }),
    createQ({ stemTemplate: "An echo shows concentric LV hypertrophy with a ground-glass appearance, low QRS voltage on ECG, and diastolic heart failure. This combination is most suggestive of:", options: ["Hypertensive heart disease", "Cardiac amyloidosis", "Athlete's heart", "Aortic stenosis"], correctAnswer: 1, rationale: "The combination of LVH on echo with low voltage on ECG (voltage-mass mismatch) is classic for infiltrative cardiomyopathy, particularly cardiac amyloidosis. In hypertensive LVH and AS, ECG typically shows high voltage. The ground-glass (sparkling) myocardial appearance is characteristic of amyloid.", learningObjective: "Identify voltage-mass mismatch in cardiac amyloidosis", blueprintCategory: "Pathology Recognition", subtopic: "Cardiomyopathies", difficulty: 4, cognitiveLevel: "analysis", questionType: "clinical-case", exam: "RDCS-AE", regionScope: "BOTH" }),
    createQ({ stemTemplate: "Fabry disease on echocardiography characteristically shows:", options: ["Dilated cardiomyopathy", "Concentric LV hypertrophy (often severe) with a binary appearance of the endocardium on advanced imaging", "Isolated RV dilation", "Normal echo"], correctAnswer: 1, rationale: "Fabry disease (X-linked lysosomal storage disorder) causes progressive concentric LVH due to glycosphingolipid accumulation in cardiomyocytes. The hypertrophy can be severe (>15 mm) and may mimic HCM. Advanced imaging (strain, T1 mapping on MRI) helps distinguish it from other causes of LVH.", learningObjective: "Identify echo features of Fabry disease", blueprintCategory: "Pathology Recognition", subtopic: "Cardiomyopathies", difficulty: 5, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" }),
    createQ({ stemTemplate: "Endomyocardial fibrosis on echocardiography shows:", options: ["Global LV dilation", "Apical obliteration with thrombus and dense fibrosis of the endocardium", "Normal echo", "Pericardial calcification"], correctAnswer: 1, rationale: "Endomyocardial fibrosis shows progressive fibrosis and thickening of the endocardium, particularly at the apex and near the AV valves, leading to apical obliteration often with organized thrombus. It causes restrictive physiology and may involve mitral/tricuspid valves causing regurgitation.", learningObjective: "Describe echo findings of endomyocardial fibrosis", blueprintCategory: "Pathology Recognition", subtopic: "Cardiomyopathies", difficulty: 5, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" }),
    createQ({ stemTemplate: "In a Canadian echo lab, the sonographer identifies what appears to be a left atrial thrombus on TTE. Per CSCT standards, the appropriate next step is:", options: ["Ignore it if the patient is on anticoagulation", "Immediately notify the interpreting cardiologist and recommend TEE for confirmation", "Document it and send the patient home", "Perform cardioversion"], correctAnswer: 1, rationale: "Per Canadian echo practice standards, identification of a potential LA thrombus is a critical finding requiring immediate physician notification. TEE is recommended for confirmation given its superior sensitivity for LA and LAA thrombus detection. Clinical management decisions rest with the interpreting physician.", learningObjective: "Apply Canadian protocols for critical echo findings", blueprintCategory: "Pathology Recognition", subtopic: "CSCT Exam Preparation", difficulty: 3, cognitiveLevel: "application", questionType: "multiple-choice", exam: "CSCT-CARDIAC", regionScope: "CAN" }),
    createQ({ stemTemplate: "On the ARDMS RDCS-AE exam, the Ultrasound Physics domain accounts for approximately what percentage?", options: ["5%", "15%", "25%", "40%"], correctAnswer: 1, rationale: "The ARDMS RDCS-AE exam allocates approximately 15% to Ultrasound Physics/Instrumentation (SPI content). The remaining content covers Anatomy/Physiology (20%), Pathology Recognition (25%), Hemodynamic Measurements (25%), and Patient Care (15%).", learningObjective: "Understand RDCS-AE exam content distribution", blueprintCategory: "Ultrasound Physics", subtopic: "ARDMS Exam Content", difficulty: 1, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "US" }),
    createQ({ stemTemplate: "The CCI RCS credential differs from the ARDMS RDCS in that:", options: ["They test completely different content", "CCI RCS is offered by Cardiovascular Credentialing International and may have different eligibility requirements, though content domains overlap significantly", "RDCS does not test hemodynamics", "RCS does not require clinical experience"], correctAnswer: 1, rationale: "Both the CCI RCS and ARDMS RDCS test cardiac sonography competency with similar content domains. The main differences are in the credentialing organization, eligibility pathways, and specific exam format. Content overlap is substantial, and both are recognized for clinical practice.", learningObjective: "Compare CCI RCS and ARDMS RDCS credentials", blueprintCategory: "Anatomy/Physiology", subtopic: "CCI RCS Exam Content", difficulty: 2, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "CCI-RCS", regionScope: "US" }),
    createQ({ stemTemplate: "A Canadian sonographer discovers an aortic root measuring 52 mm in a patient with known Marfan syndrome. Per Canadian guidelines, this finding:", options: ["Is within normal limits", "Requires immediate urgent communication to the referring physician and interpreting cardiologist", "Can be reported routinely", "Is only significant if symptoms are present"], correctAnswer: 1, rationale: "An aortic root of 52 mm in Marfan syndrome is at or near the threshold for prophylactic surgical repair (>50 mm in Marfan, or >45 mm with risk factors). This is a critical finding requiring urgent communication per Canadian echo reporting standards.", learningObjective: "Apply urgent communication protocols for critical aortic measurements in Canada", blueprintCategory: "Pathology Recognition", subtopic: "CSCT Exam Preparation", difficulty: 3, cognitiveLevel: "application", questionType: "multiple-choice", exam: "CSCT-CARDIAC", regionScope: "CAN" }),
    createQ({ stemTemplate: "The thermal index (TI) in echocardiography measures:", options: ["Cavitation risk", "Temperature rise potential in tissue", "Image resolution", "Frame rate"], correctAnswer: 1, rationale: "TI estimates the potential temperature rise in tissue from ultrasound exposure. TI = power used / power needed to raise tissue 1°C. TIS (soft tissue), TIB (bone), and TIC (cranial) are specific indices. ALARA principle applies to minimize thermal effects.", learningObjective: "Define the thermal index", blueprintCategory: "Ultrasound Physics", subtopic: "Echo Imaging Physics", difficulty: 3, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" }),
    createQ({ stemTemplate: "In assessing LV dyssynchrony for CRT candidacy, which echo parameter is used?", options: ["LVEF alone", "Septal-to-posterior wall motion delay, speckle tracking mechanical dyssynchrony indices", "Aortic valve area", "TR velocity"], correctAnswer: 1, rationale: "LV dyssynchrony assessment for cardiac resynchronization therapy (CRT) uses: septal-to-posterior wall delay (M-mode), tissue Doppler-based time-to-peak velocity delays, and speckle tracking-based mechanical dyssynchrony indices (radial, longitudinal, circumferential strain delays). However, current guidelines primarily use LBBB morphology and QRS duration, with echo as supplementary.", learningObjective: "Describe echo assessment of LV dyssynchrony", blueprintCategory: "Hemodynamic Measurements", subtopic: "Advanced Echo Techniques", difficulty: 5, cognitiveLevel: "comprehension", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" }),
    createQ({ stemTemplate: "An echo shows calcification of the mitral annulus extending onto the base of the posterior leaflet. This may cause:", options: ["Mitral stenosis from restricted leaflet motion", "Aortic regurgitation", "Tricuspid stenosis", "Pulmonic regurgitation"], correctAnswer: 0, rationale: "Mitral annular calcification (MAC) can restrict leaflet motion, particularly the posterior leaflet, causing a functional mitral stenosis. It can also contribute to MR by preventing proper annular contraction. Severe MAC may create a caseous calcification (echolucent mass within the calcification).", learningObjective: "Describe hemodynamic consequences of MAC", blueprintCategory: "Pathology Recognition", subtopic: "Valvular Disease Assessment", difficulty: 3, cognitiveLevel: "analysis", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" }),
  ];
}

export function generateBatch5(): GeneratedQ[] {
  return [
    createQ({ stemTemplate: "A patient presents with acute inferior MI. Echo shows akinesis of the inferior wall and RV dilation with reduced TAPSE. The most likely culprit artery is:", options: ["LAD", "LCx", "Proximal RCA", "Diagonal branch"], correctAnswer: 2, rationale: "Inferior wall akinesis with RV involvement indicates proximal RCA occlusion (proximal to the RV marginal branches). RV infarction occurs in 30-50% of inferior MIs and requires preload optimization with IV fluids. Avoid nitroglycerin and diuretics.", learningObjective: "Correlate RV involvement with proximal RCA occlusion", blueprintCategory: "Pathology Recognition", subtopic: "Ischemic Heart Disease", difficulty: 3, cognitiveLevel: "analysis", questionType: "clinical-case", exam: "RDCS-AE", regionScope: "BOTH" }),
    createQ({ stemTemplate: "Dobutamine stress echo is preferred over exercise stress echo when:", options: ["The patient can exercise normally", "The patient cannot exercise adequately due to physical limitations", "There are no contraindications to exercise", "The patient is young and healthy"], correctAnswer: 1, rationale: "Dobutamine stress echo is used when patients cannot exercise adequately (orthopedic limitations, peripheral vascular disease, deconditioning, neurological conditions). Exercise stress is preferred when possible because it provides additional prognostic information (exercise capacity, hemodynamic response).", learningObjective: "Select appropriate stress echo modality", blueprintCategory: "Pathology Recognition", subtopic: "Stress Echocardiography", difficulty: 2, cognitiveLevel: "application", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" }),
    createQ({ stemTemplate: "A stress echo shows biphasic response (improvement at low-dose dobutamine, deterioration at peak dose) in the anterior wall. This suggests:", options: ["Normal myocardium", "Infarcted, non-viable myocardium", "Viable, ischemic myocardium (hibernating myocardium)", "Artifact"], correctAnswer: 2, rationale: "Biphasic response (improvement at low dose, worsening at peak dose) indicates viable but jeopardized myocardium. Low-dose dobutamine recruits contractile reserve in hibernating myocardium, while peak dose induces ischemia. This pattern predicts functional recovery after revascularization.", learningObjective: "Interpret biphasic response on dobutamine stress echo", blueprintCategory: "Pathology Recognition", subtopic: "Stress Echocardiography", difficulty: 4, cognitiveLevel: "analysis", questionType: "clinical-case", exam: "RDCS-AE", regionScope: "BOTH" }),
    createQ({ stemTemplate: "The normal aortic valve Doppler index (DVI) range is:", options: ["<0.25", "0.25-0.50", ">0.50", "0.75-1.00"], correctAnswer: 2, rationale: "Normal DVI (LVOT VTI/AV VTI or LVOT Vpeak/AV Vpeak) is >0.50 (ideally approaching 1.0 for a normal valve). DVI 0.25-0.50 suggests moderate AS. DVI <0.25 indicates severe AS.", learningObjective: "State normal DVI range", blueprintCategory: "Hemodynamic Measurements", subtopic: "Hemodynamic Calculations", difficulty: 2, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" }),
    createQ({ stemTemplate: "PISA (proximal isovelocity surface area) is based on the principle of:", options: ["Bernoulli equation", "Conservation of mass (flow convergence)", "Laplace law", "Ohm's law"], correctAnswer: 1, rationale: "PISA is based on the principle of conservation of mass — flow approaching a regurgitant orifice must equal flow through the orifice. As blood accelerates toward the orifice, it forms concentric hemispheric shells of equal velocity that can be visualized with color Doppler aliasing.", learningObjective: "Explain the PISA principle", blueprintCategory: "Hemodynamic Measurements", subtopic: "Hemodynamic Calculations", difficulty: 3, cognitiveLevel: "comprehension", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" }),
    createQ({ stemTemplate: "For severe TR, the EROA threshold is:", options: ["≥0.10 cm²", "≥0.20 cm²", "≥0.30 cm²", "≥0.40 cm²"], correctAnswer: 3, rationale: "Severe TR criteria include: EROA ≥0.40 cm², regurgitant volume ≥45 mL, vena contracta ≥7 mm, dense triangular CW signal, systolic hepatic vein flow reversal, and significant RA/RV dilation.", learningObjective: "State EROA criteria for severe TR", blueprintCategory: "Hemodynamic Measurements", subtopic: "Hemodynamic Calculations", difficulty: 3, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" }),
    createQ({ stemTemplate: "In the 2016 ASE diastolic function guidelines, how many variables are used to determine elevated filling pressures?", options: ["2", "3", "4", "6"], correctAnswer: 2, rationale: "The 2016 ASE/EACVI algorithm uses 4 variables: E/e' ratio (>14), e' velocity (septal <7, lateral <10), TR velocity (>2.8 m/s), and LA volume index (>34 mL/m²). If ≥3 of 4 are positive, filling pressures are elevated. If ≥3 are negative, normal. Otherwise indeterminate.", learningObjective: "Apply the 2016 ASE diastolic function algorithm", blueprintCategory: "Hemodynamic Measurements", subtopic: "Diastolic Function Assessment", difficulty: 4, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" }),
    createQ({ stemTemplate: "A sonographer performing a CSCT exam will be tested on their ability to:", options: ["Perform interventional procedures", "Acquire diagnostic-quality images and recognize normal vs abnormal findings", "Interpret final reports", "Prescribe medications based on echo findings"], correctAnswer: 1, rationale: "The CSCT exam tests the sonographer's ability to acquire high-quality diagnostic images, optimize them appropriately, perform standard measurements, and recognize normal vs abnormal findings. Final interpretation, prescribing, and interventional procedures are outside the sonographer's scope.", learningObjective: "Define CSCT exam competency expectations", blueprintCategory: "Anatomy/Physiology", subtopic: "CSCT Exam Preparation", difficulty: 1, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "CSCT-CARDIAC", regionScope: "CAN" }),
    createQ({ stemTemplate: "A Chiari network in the right atrium is best distinguished from a thrombus by:", options: ["Its color", "Its mobility, thin filamentous appearance, and attachment to the Eustachian valve/crista terminalis area", "Its position in the left atrium", "Its calcification"], correctAnswer: 1, rationale: "Chiari networks are thin, highly mobile, fenestrated structures attached to the Eustachian valve or crista terminalis area. They are distinguished from thrombi by their thin, web-like appearance, high mobility, and characteristic RA location. Thrombi are typically denser, less mobile, and may be pedunculated.", learningObjective: "Differentiate Chiari network from RA thrombus", blueprintCategory: "Anatomy/Physiology", subtopic: "Cardiac Anatomy", difficulty: 3, cognitiveLevel: "analysis", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" }),
    createQ({ stemTemplate: "A lipomatous hypertrophy of the interatrial septum characteristically shows:", options: ["Uniform thickening of the entire septum", "Bilobed thickening of the septum with sparing of the fossa ovalis", "Thinning of the septum", "A discrete mass within the LA"], correctAnswer: 1, rationale: "Lipomatous hypertrophy of the IAS shows fatty infiltration causing bilobed (dumbbell-shaped) thickening of the septum with characteristic sparing of the fossa ovalis. It is benign and typically >2 cm thick. It can be confirmed by its fat-density on CT.", learningObjective: "Identify lipomatous hypertrophy of the IAS", blueprintCategory: "Anatomy/Physiology", subtopic: "Cardiac Anatomy", difficulty: 4, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" }),
    createQ({ stemTemplate: "A transesophageal echo (TEE) is indicated before cardioversion because:", options: ["It improves EF measurement", "It rules out LAA thrombus which would contraindicate cardioversion due to embolic risk", "It assesses aortic stenosis better", "It is required by law"], correctAnswer: 1, rationale: "TEE before cardioversion detects LAA thrombus that could embolize during rhythm conversion. If thrombus is found, cardioversion is deferred and anticoagulation is continued for at least 3-4 weeks before reattempting. TEE sensitivity for LAA thrombus is >95%.", learningObjective: "State indications for TEE before cardioversion", blueprintCategory: "Pathology Recognition", subtopic: "Cardiac Masses", difficulty: 3, cognitiveLevel: "comprehension", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" }),
    createQ({ stemTemplate: "In assessment of LV volumes by Simpson's biplane method, which two views are used?", options: ["PLAX and PSAX", "A4C and A2C", "Subcostal and suprasternal", "A4C and A3C"], correctAnswer: 1, rationale: "The biplane Simpson's (method of disks) uses the apical four-chamber (A4C) and apical two-chamber (A2C) views to trace the LV endocardium at end-diastole and end-systole. The LV is divided into stacked disks whose summed volumes calculate EDV and ESV.", learningObjective: "Identify views for biplane Simpson's method", blueprintCategory: "Hemodynamic Measurements", subtopic: "Chamber Quantification", difficulty: 2, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" }),
    createQ({ stemTemplate: "The Coanda effect can cause underestimation of which valvular condition?", options: ["Aortic stenosis", "Eccentric mitral regurgitation", "Mitral stenosis", "Pulmonic stenosis"], correctAnswer: 1, rationale: "The Coanda effect causes eccentric regurgitant jets to hug the wall, appearing smaller on color Doppler than centrally directed jets of the same severity. This is particularly problematic for eccentric MR jets (e.g., from flail leaflets or prolapse). EROA/PISA should be used instead of jet area.", learningObjective: "Identify Coanda effect in MR assessment", blueprintCategory: "Pathology Recognition", subtopic: "Valvular Disease Assessment", difficulty: 3, cognitiveLevel: "comprehension", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" }),
    createQ({ stemTemplate: "A left atrial appendage velocity of <20 cm/s by TEE suggests:", options: ["Normal LAA function", "High thromboembolic risk", "Fast heart rate", "Mitral stenosis"], correctAnswer: 1, rationale: "LAA emptying velocity <20 cm/s (measured by PW Doppler at the LAA orifice) indicates significant stasis and high thromboembolic risk, even if no formed thrombus is visible. Normal LAA velocity is >40 cm/s. Low velocity is common in AF and associated with SEC.", learningObjective: "Interpret LAA emptying velocity", blueprintCategory: "Pathology Recognition", subtopic: "Cardiac Masses", difficulty: 4, cognitiveLevel: "analysis", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" }),
    createQ({ stemTemplate: "The normal pulmonary vein flow pattern consists of:", options: ["Only diastolic forward flow", "Systolic forward (S), diastolic forward (D), and atrial reversal (Ar) waves", "Continuous forward flow without variation", "Only systolic forward flow"], correctAnswer: 1, rationale: "Normal PV flow has three components: S wave (systolic forward flow), D wave (diastolic forward flow), and Ar wave (atrial contraction reversal). S ≥ D in normal individuals. S < D or S reversal suggests elevated LA pressure or severe MR.", learningObjective: "Describe normal pulmonary vein flow pattern", blueprintCategory: "Hemodynamic Measurements", subtopic: "Diastolic Function Assessment", difficulty: 3, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" }),
    createQ({ stemTemplate: "A patient's pulmonary vein Ar duration is 30 ms longer than the mitral A wave duration. This finding suggests:", options: ["Normal filling pressures", "Elevated LV end-diastolic pressure", "Mitral stenosis", "Low cardiac output"], correctAnswer: 1, rationale: "PV Ar duration exceeding mitral A duration by ≥30 ms is a marker of elevated LVEDP. When atrial contraction encounters a stiff LV (elevated EDP), blood is redirected backward into the pulmonary veins, prolonging the Ar wave. This is an important supplementary parameter for filling pressure assessment.", learningObjective: "Interpret PV Ar - mitral A duration difference", blueprintCategory: "Hemodynamic Measurements", subtopic: "Diastolic Function Assessment", difficulty: 4, cognitiveLevel: "analysis", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" }),
    createQ({ stemTemplate: "In a patient with an LVAD (left ventricular assist device), the echo assessment should include:", options: ["Only LVEF", "Aortic valve opening frequency, RV function, inflow/outflow cannula interrogation, and septal position", "Only Doppler of the outflow cannula", "Only chamber dimensions"], correctAnswer: 1, rationale: "LVAD echo assessment includes: aortic valve opening frequency (should open intermittently or not at all with full unloading), RV function (critical for LVAD outcomes), inflow cannula position and velocity, outflow cannula velocities, LV size, septal position (leftward shift suggests RV overload), and pericardial effusion.", learningObjective: "Describe LVAD echo assessment components", blueprintCategory: "Hemodynamic Measurements", subtopic: "Advanced Echo Techniques", difficulty: 5, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" }),
    createQ({ stemTemplate: "The attenuation coefficient of ultrasound in soft tissue at 1 MHz is approximately:", options: ["0.1 dB/cm", "0.5 dB/cm/MHz", "1.0 dB/cm/MHz", "5.0 dB/cm/MHz"], correctAnswer: 1, rationale: "Attenuation in soft tissue is approximately 0.5 dB/cm/MHz (or 0.5 dB per cm per MHz of frequency). At 3 MHz and 10 cm depth, total attenuation ≈ 0.5 × 3 × 10 × 2 (round trip) = 30 dB. This rapid attenuation at higher frequencies limits penetration depth.", learningObjective: "State the attenuation coefficient in soft tissue", blueprintCategory: "Ultrasound Physics", subtopic: "Echo Imaging Physics", difficulty: 3, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" }),
    createQ({ stemTemplate: "In color Doppler, variance is displayed as:", options: ["Red", "Blue", "Green or mosaic pattern (indicating turbulence)", "White"], correctAnswer: 2, rationale: "Color Doppler variance (turbulence) is displayed as green or as a mosaic pattern when added to the standard red-blue map. Variance indicates a wide range of velocities within the sample volume, as seen in stenotic jets, regurgitant jets, and shunt flows.", learningObjective: "Interpret color Doppler variance display", blueprintCategory: "Ultrasound Physics", subtopic: "Doppler Ultrasound", difficulty: 2, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" }),
    createQ({ stemTemplate: "Time gain compensation (TGC) adjusts:", options: ["Transmitted power", "Signal amplification at different depths to compensate for attenuation", "Transducer frequency", "Frame rate"], correctAnswer: 1, rationale: "TGC increases gain (amplification) at progressively greater depths to compensate for the increased attenuation of deeper echoes. Without TGC, deeper structures would appear darker. Each slider controls gain at a specific depth zone, allowing customized compensation.", learningObjective: "Explain TGC function", blueprintCategory: "Ultrasound Physics", subtopic: "Echo Imaging Physics", difficulty: 2, cognitiveLevel: "comprehension", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" }),
    createQ({ stemTemplate: "Strain echocardiography can detect subclinical cardiotoxicity from chemotherapy when GLS drops by:", options: [">5% relative decrease from baseline", ">10% relative decrease from baseline", ">15% relative decrease from baseline with GLS below normal limits", ">25% relative decrease from baseline"], correctAnswer: 2, rationale: "A >15% relative decrease in GLS from baseline, especially when GLS falls below the lower limit of normal (-18%), is considered a significant marker of subclinical cardiotoxicity. This typically precedes the drop in LVEF and allows early intervention (cardioprotective agents or chemotherapy modification).", learningObjective: "Apply GLS criteria for chemotherapy cardiotoxicity screening", blueprintCategory: "Hemodynamic Measurements", subtopic: "Advanced Echo Techniques", difficulty: 4, cognitiveLevel: "application", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" }),
    createQ({ stemTemplate: "A Canadian sonographer discovers a pericardial effusion with signs of tamponade during an outpatient echo. The CSCT-aligned response is:", options: ["Complete the routine study and send the report through normal channels", "Immediately notify the interpreting physician and ensure the patient is monitored while arrangements are made for urgent pericardiocentesis", "Ask the patient to return the next day", "Document findings and have the patient follow up with their family doctor"], correctAnswer: 1, rationale: "Cardiac tamponade is a medical emergency. Canadian sonographer standards require immediate physician notification for life-threatening findings. The sonographer should ensure the patient is not discharged and remains monitored while the physician arranges urgent intervention (pericardiocentesis or surgical drainage).", learningObjective: "Respond to cardiac tamponade per Canadian emergency protocols", blueprintCategory: "Pathology Recognition", subtopic: "CSCT Exam Preparation", difficulty: 3, cognitiveLevel: "application", questionType: "multiple-choice", exam: "CSCT-CARDIAC", regionScope: "CAN" }),
  ];
}

export function generateAllBatches(): GeneratedQ[] {
  return [...generateBatch4(), ...generateBatch5()];
}
